/* eslint-disable @next/next/no-img-element */
"use client";

import { ReactElement, useEffect, useState } from "react";
import MainText from "../text/MainText";
import SecondaryText from "../text/SecondaryText";
import { images } from "@/data/images";
import { skills } from "@/data/skills";
import Button from "../reusable/Button";
import { useModal } from "@/providers/ModalProvider";
import Image from "next/image"; // Імпортуємо Image з Next.js

interface HeroProps {
  dict: {
    greet: string;
    i: string;
    oleksandr: string;
    heroText: string;
    writeMe: string;
  };
}

const ALL_SKILLS = Object.values(skills).flat();

export default function Hero({ dict }: HeroProps) {
  const [skillsToDisplay, setSkillsToDisplay] = useState<string[]>(ALL_SKILLS);
  const { openModal } = useModal();

  useEffect(() => {
    const timer = setTimeout(() => {
      setSkillsToDisplay([...ALL_SKILLS].sort(() => Math.random() - 0.5));
    }, 10);

    return () => clearTimeout(timer);
  }, []);

  const socialLinks = [
    {
      icon: InstagramSvg,
      label: "zaiiats",
      color: "rgb(221,42,123)",
      onClick: () => window.open("https://www.instagram.com/zaiiats/"),
    },
    {
      icon: TelegramSvg,
      label: "zaiiats",
      color: "rgb(42,171,238)",
      onClick: () => window.open("https://t.me/zaiiats/"),
    },
    {
      icon: GithubSvg,
      label: "zaiiats",
      color: "rgb(105,120,136)",
      onClick: () => window.open("https://github.com/zaiiats"),
    },
    {
      icon: MailSvg,
      label: "zaiatsoleksandry@gmail.com",
      color: "rgb(248,214,111)",
      onClick: () => {
        window.location.href = "mailto:zaiatsoleksandry@gmail.com";
      },
    },
  ];

  return (
    <section
      id="home"
      className="relative grid w-full h-[calc(100dvh-2rem)] overflow-hidden px-8 pb-8 select-none"
    >
      <div className="relative z-1 flex flex-col items-center justify-center gap-20">
        <div className="relative z-1 flex w-full max-w-[70%] flex-col items-center text-center gap-8">
          <MainText isGlowing={true} size="huge">
            {dict.greet}
          </MainText>
          <SecondaryText size="medium">
            {dict.i} {dict.oleksandr} – {dict.heroText}
          </SecondaryText>
        </div>

        <Button
          onClick={() =>
            openModal(
              <div className="flex w-full flex-col overflow-hidden rounded-b-2xl isolate">
                {socialLinks.map((link, index) => (
                  <SocialLinkCard key={index} {...link} />
                ))}
              </div>,
            )
          }
          text={dict.writeMe}
        />
      </div>

      <div
        className="absolute left-1/2 top-1/2 flex -translate-x-1/2 -translate-y-1/2 flex-col gap-7.5 
        [&>div:nth-child(even)]:animate-[move-right_62s_ease-in-out_infinite_alternate] 
        [&>div:nth-child(odd)]:animate-[move-left_62s_ease-in-out_infinite_alternate]"
      >
        {images.map((imageColumn, i) => (
          <div
            key={`imageColumn-${i}`}
            className="flex h-[20dvh] w-max gap-7.5 opacity-20"
          >
            {imageColumn.map((image, j) => (
              /* Замінено <img> на <Image> зі збереженням твоїх оригінальних класів */
              <Image
                src={image.startsWith("/") ? image : `/${image}`}
                key={`image-${i}-${j}`}
                alt=""
                // Передаємо базові розміри для задовільнення вимог Next.js
                width={300}
                height={200}
                // Магічний пропс у Next.js, який дозволяє перевизначати розміри через CSS класи
                style={{ width: "auto", height: "100%" }}
                // Твої класи залишилися абсолютно без змін
                className="inline h-full w-auto max-w-none shrink-0 object-contain"
                // Вказуємо розмір для оптимізації, оскільки картинки маленькі у фоні
                sizes="20dvh"
              />
            ))}
          </div>
        ))}
      </div>

      <div className="absolute bottom-16 left-0 flex w-full items-center justify-start overflow-hidden bg-(--accent-color) px-4 py-2">
        <div className="flex w-max items-center gap-2.5 whitespace-nowrap animate-[scrollSkills_32s_linear_infinite]">
          {[...skillsToDisplay, ...skillsToDisplay].map((skill, i) => (
            <span
              key={i}
              className="flex items-center gap-2.5 text-[0.75rem] text-white opacity-90 [transition:var(--transition)]"
            >
              {skill} <span>•</span>
            </span>
          ))}
        </div>
      </div>
    </section>
  );
}

interface SocialLinkCardProps {
  onClick: () => void;
  label: string;
  icon: ReactElement;
  color: string;
}

export function SocialLinkCard({
  onClick,
  icon,
  label,
  color,
}: SocialLinkCardProps) {
  return (
    <div
      onClick={onClick}
      className="group relative flex items-center p-2 gap-2 overflow-hidden cursor-pointer"
    >
      <div className="underline p-2 flex">
        {label}
        {LinkSvg}
      </div>
      <div className="flex ml-auto items-center justify-center w-15 h-15">
        <div
          style={{
            filter: `drop-shadow(0 0 15px ${color}) drop-shadow(0 0 20px ${color}) drop-shadow(0 0 30px ${color}) drop-shadow(0 0 50px ${color}) drop-shadow(0 0 90px ${color})`,
          }}
          className="transition-transform duration-300 ease-out group-hover:scale-150 group-hover:opacity-100 opacity-80 flex items-center justify-center will-change-transform"
        >
          {icon}
        </div>
      </div>
    </div>
  );
}

